import React, { useEffect, useState } from "react";

function Orders({ apiBase = "http://localhost:8080", getStatusClass }) {
  const [orders, setOrders] = useState([]);
  const [loading, setLoading] = useState(true);
  const [message, setMessage] = useState("");

  useEffect(() => {
    loadOrders();

    const interval = setInterval(() => {
      loadOrders(false);
    }, 5000);

    return () => clearInterval(interval);
  }, []);

  async function loadOrders(showLoader = true) {
    if (showLoader) {
      setLoading(true);
    }

    try {
      const response = await fetch(`${apiBase}/orders`);
      const data = await response.json();
      setOrders(Array.isArray(data) ? data : []);
    } catch (error) {
      setMessage("Could not load orders.");
      setOrders([]);
    } finally {
      if (showLoader) {
        setLoading(false);
      }
    }
  }

  async function updateOrderStatus(order, newStatus) {
    try {
      const response = await fetch(`${apiBase}/orders/${order.id}`, {
        method: "PUT",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          foodName: order.foodName,
          quantity: order.quantity,
          totalPrice: order.totalPrice,
          status: newStatus,
          customerName: order.customerName,
          paymentMethod: order.paymentMethod,
          orderType: order.orderType,
          pickupSlot: order.pickupSlot,
          notes: order.notes,
          waitingTime: order.waitingTime
        })
      });

      if (!response.ok) throw new Error("update failed");

      setMessage("Order status updated.");
      loadOrders(false);
    } catch (error) {
      setMessage("Could not update order status.");
    }
  }

  return (
    <div className="section-gap">
      <section className="content-card">
        <div className="section-title-row">
          <div>
            <h2>Orders</h2>
            <p>Track live orders and monitor preparation status.</p>
          </div>
        </div>

        {message && <div className="message-banner">{message}</div>}

        {loading ? (
          <div className="empty-box">Loading orders...</div>
        ) : orders.length === 0 ? (
          <div className="empty-box">No orders available.</div>
        ) : (
          <div className="orders-grid">
            {orders.map((order) => (
              <div className="order-card" key={order.id}>
                <div className="order-card-top">
                  <div>
                    <h3>{order.foodName}</h3>
                    <p><strong>Student:</strong> {order.customerName}</p>
                    <p><strong>Quantity:</strong> {order.quantity}</p>
                    <p><strong>Total:</strong> ₹{order.totalPrice}</p>
                    <p><strong>Payment:</strong> {order.paymentMethod}</p>
                    <p><strong>Order Type:</strong> {order.orderType}</p>
                    <p><strong>Pickup Slot:</strong> {order.pickupSlot}</p>
                    <p><strong>Waiting Time:</strong> {order.waitingTime} mins</p>
                    {order.notes && <p><strong>Notes:</strong> {order.notes}</p>}
                  </div>

                  <span
                    className={
                      getStatusClass
                        ? getStatusClass(order.status)
                        : "status-badge pending"
                    }
                  >
                    {order.status}
                  </span>
                </div>

                <div className="action-row wrap-row">
                  <button
                    className="secondary-btn"
                    onClick={() => updateOrderStatus(order, "Pending")}
                  >
                    Pending
                  </button>
                  <button
                    className="secondary-btn"
                    onClick={() => updateOrderStatus(order, "Preparing")}
                  >
                    Preparing
                  </button>
                  <button
                    className="primary-btn"
                    onClick={() => updateOrderStatus(order, "Ready")}
                  >
                    Ready
                  </button>
                  <button
                    className="secondary-btn"
                    onClick={() => updateOrderStatus(order, "Completed")}
                  >
                    Completed
                  </button>
                  <button
                    className="danger-btn"
                    onClick={() => updateOrderStatus(order, "Cancelled")}
                  >
                    Cancel
                  </button>
                </div>
              </div>
            ))}
          </div>
        )}
      </section>
    </div>
  );
}

export default Orders;
